import{_ as e,o as a,c as i,ai as n}from"./chunks/framework.CsYGeNYI.js";const g=JSON.parse('{"title":"Debugging","description":"","frontmatter":{"summary":"Debugging tools: watch mode, raw model streams, and tracing reasoning leakage","read_when":["You need to inspect raw model output for reasoning leakage","You want to run the Gateway in watch mode while iterating","You need a repeatable debugging workflow"],"title":"Debugging"},"headers":[],"relativePath":"help/debugging.md","filePath":"help/debugging.md","lastUpdated":1771906665000}'),t={name:"help/debugging.md"};function l(p,s,o,d,r,h){return a(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="debugging" tabindex="-1"><a class="header-anchor" href="#debugging">#</a> Debugging</h1><p>This page covers debugging helpers for streaming output, especially when a provider mixes reasoning into normal text.</p><h2 id="runtime-debug-overrides" tabindex="-1"><a class="header-anchor" href="#runtime-debug-overrides">#</a> Runtime debug overrides</h2><p>Use <code>/debug</code> in chat to set <strong>runtime-only</strong> config overrides (memory, not disk). <code>/debug</code> is disabled by default; enable with <code>commands.debug: true</code>. This is handy when you need to toggle obscure settings without editing <code>opensoul.json</code>.</p><p>Examples:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/debug show</span></span>
<span class="line"><span>/debug set messages.responsePrefix=&quot;[opensoul]&quot;</span></span>
<span class="line"><span>/debug unset messages.responsePrefix</span></span>
<span class="line"><span>/debug reset</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><code>/debug reset</code> clears all overrides and returns to the on-disk config.</p><h2 id="gateway-watch-mode" tabindex="-1"><a class="header-anchor" href="#gateway-watch-mode">#</a> Gateway watch mode</h2><p>For fast iteration, run the gateway under the file watcher:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:watch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This maps to:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tsx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> watch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/entry.ts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Add any gateway CLI flags after <code>gateway:watch</code> and they will be passed through on each restart.</p><h2 id="dev-profile-dev-gateway-dev" tabindex="-1"><a class="header-anchor" href="#dev-profile-dev-gateway-dev">#</a> Dev profile + dev gateway (--dev)</h2><p>Use the dev profile to isolate state and spin up a safe, disposable setup for debugging. There are <strong>two</strong> <code>--dev</code> flags:</p><ul><li><strong>Global <code>--dev</code> (profile):</strong> isolates state under <code>~/.opensoul-dev</code> and defaults the gateway port to <code>19001</code> (derived ports shift with it).</li><li><strong><code>gateway --dev</code>: tells the Gateway to auto-create a default config + workspace</strong> when missing (and skip BOOTSTRAP.md).</li></ul><p>Recommended flow (dev profile + dev bootstrap):</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:dev</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENSOUL_PROFILE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">dev</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tui</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>If you don’t have a global install yet, run the CLI via <code>pnpm opensoul ...</code>.</p><p>What this does:</p><ol><li><p><strong>Profile isolation</strong> (global <code>--dev</code>)</p><ul><li><code>OPENSOUL_PROFILE=dev</code></li><li><code>OPENSOUL_STATE_DIR=~/.opensoul-dev</code></li><li><code>OPENSOUL_CONFIG_PATH=~/.opensoul-dev/opensoul.json</code></li><li><code>OPENSOUL_GATEWAY_PORT=19001</code> (browser/canvas shift accordingly)</li></ul></li><li><p><strong>Dev bootstrap</strong> (<code>gateway --dev</code>)</p><ul><li>Writes a minimal config if missing (<code>gateway.mode=local</code>, bind loopback).</li><li>Sets <code>agent.workspace</code> to the dev workspace.</li><li>Sets <code>agent.skipBootstrap=true</code> (no BOOTSTRAP.md).</li><li>Seeds the workspace files if missing: <code>AGENTS.md</code>, <code>SOUL.md</code>, <code>TOOLS.md</code>, <code>IDENTITY.md</code>, <code>USER.md</code>, <code>HEARTBEAT.md</code>.</li><li>Default identity: <strong>C3‑PO</strong> (protocol droid).</li><li>Skips channel providers in dev mode (<code>OPENSOUL_SKIP_CHANNELS=1</code>).</li></ul></li></ol><p>Reset flow (fresh start):</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:dev:reset</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Note: <code>--dev</code> is a <strong>global</strong> profile flag and gets eaten by some runners. If you need to spell it out, use the env var form:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENSOUL_PROFILE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">dev</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --reset</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>--reset</code> wipes config, credentials, sessions, and the dev workspace (using <code>trash</code>, not <code>rm</code>), then recreates the default dev setup.</p><p>Tip: if a non‑dev gateway is already running (launchd/systemd), stop it first:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="raw-stream-logging-opensoul" tabindex="-1"><a class="header-anchor" href="#raw-stream-logging-opensoul">#</a> Raw stream logging (OpenSoul)</h2><p>OpenSoul can log the <strong>raw assistant stream</strong> before any filtering/formatting. This is the best way to see whether reasoning is arriving as plain text deltas (or as separate thinking blocks).</p><p>Enable it via CLI:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:watch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --raw-stream</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Optional path override:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:watch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --raw-stream</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --raw-stream-path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opensoul/logs/raw-stream.jsonl</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Equivalent env vars:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENSOUL_RAW_STREAM</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENSOUL_RAW_STREAM_PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">~/.opensoul/logs/raw-stream.jsonl</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Default file:</p><p><code>~/.opensoul/logs/raw-stream.jsonl</code></p><h2 id="raw-chunk-logging-pi-mono" tabindex="-1"><a class="header-anchor" href="#raw-chunk-logging-pi-mono">#</a> Raw chunk logging (pi-mono)</h2><p>To capture <strong>raw OpenAI-compat chunks</strong> before they are parsed into blocks, pi-mono exposes a separate logger:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PI_RAW_STREAM</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Optional path:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PI_RAW_STREAM_PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">~/.pi-mono/logs/raw-openai-completions.jsonl</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Default file:</p><p><code>~/.pi-mono/logs/raw-openai-completions.jsonl</code></p><blockquote><p>Note: this is only emitted by processes using pi-mono’s <code>openai-completions</code> provider.</p></blockquote><h2 id="safety-notes" tabindex="-1"><a class="header-anchor" href="#safety-notes">#</a> Safety notes</h2><ul><li>Raw stream logs can include full prompts, tool output, and user data.</li><li>Keep logs local and delete them after debugging.</li><li>If you share logs, scrub secrets and PII first.</li></ul>`,48)])])}const u=e(t,[["render",l]]);export{g as __pageData,u as default};
